'use client';

import Loading from '@/components/Loading';
import { Card, CardContent } from '@/components/ui/card';

import PageHeader from '@/components/page-header';
import { Icon } from '@iconify-icon/react';
import { useParams, useRouter } from 'next/navigation';
import { useGetEmployee } from '../hooks';

const EmployeeViewPage = () => {
  const params = useParams();

  const router = useRouter();

  const id = params?.id as string;

  const { data, isLoading } = useGetEmployee(id);

  const employeeDetails = data && data?.data;

  if (isLoading) return <Loading />;

  if (!employeeDetails) {
    return (
      <div className='h-full w-full gap-2 flex justify-center items-center'>
        <Icon icon={'lucide:alert-circle'} className='text-2xl text-red-500' />
        Employee not found
      </div>
    );
  }

  return (
    <div className='space-y-4 @container'>
      <div>
        <PageHeader
          title={'Employee Details'}
          backButton={true}
          onBackClick={() => router.back()}
        />
      </div>

      <Card>
        <CardContent>
          <div className='grid gap-4  grid-cols-1 @md:grid-cols-2 @lg:grid-cols-3 w-full'>
            {/* <div className='space-y-2 col-span-3'>
                <Label>Image</Label>
                <NextImageWithFallback
                  width={200}
                  height={200}
                  alt=''
                  src={mediaUrl2(employeeDetails?.image)}
                />
              </div>
              <div className='space-y-2 col-span-1'>
                <Label>Name</Label>
                <ViewValue value={employeeDetails?.name} />
              </div> */}
          </div>
        </CardContent>
      </Card>
    </div>
  );
};

export default EmployeeViewPage;
